---@class LWonderObjectCtrl
local LWonderObjectCtrl = LxClass("LWonderObjectCtrl",nil)

function LWonderObjectCtrl:LWonderObjectCtrl()
    self._objList = {}
end

function LWonderObjectCtrl:InitCtrl(root)
    self._objRoot = root
end
--[[
    local data =
    {
        key = "mainRole",
        pos = pos,
        resName = spineName,
        scale = 0.7,
        endFunc = function (spine)
        end,
        enableClick = true,
    }
]]

function LWonderObjectCtrl:MakeObject(objData)
    local key = objData.key
    local objectData = self._objList[key]
    --local endFunc = objData.endFunc
    local spine = nil
    if objectData then
        objectData.objData = objData
        if objectData.isLoaded then
            self:OnSpineLoaded(key)
        end
        spine = objectData.spine

    else
        spine = LDisplaySpine:New()
        objectData = {spine = spine,objData = objData}
        self._objList[key] = objectData
        local trans =objData.root or self._objRoot
        local spineName = objData.resName
        spine:CreateSpine(trans, spineName,LDisplaySpine.TYPE_MODEL)
        spine:SetLoadedFunction(function()
            self:OnSpineLoaded(key)
        end)
        spine:StartLoad()
    end

    return spine
end

function LWonderObjectCtrl:OnSpineLoaded(key)

    local objectData = self._objList[key]
    if not objectData then
        return
    end
    objectData.isLoaded = true
    local spine = objectData.spine
    local objData = objectData.objData
    local isLeft = objData.isLeft

    local dpTrans = spine:GetDisplayTrans()
    if not CS.IsValidObject(dpTrans) then
        return
    end
    if objData.pos then
        dpTrans.position =objData.pos
    end

    if objData.localPos then
        dpTrans.localPosition =objData.localPos
    end

    local scale =objData.scale or 1
    spine:SetScale(scale)
    local angle = objData.angle or Vector3.zero
    dpTrans.localRotation = Quaternion.Euler(angle.x,angle.y,angle.z)
    local sorting = objData.sorting or 0
    spine:SetRenderOrder(sorting)
    if isLeft ~= nil then
        spine:SetFlipX(isLeft)
    end

    local layer = objData.layer
    if layer then
        spine:SetRenderLayer(layer)
    end

    local collider = CS.FindTrans(dpTrans,"Collider")
    local showCollider = objData.enableClick or false
    CS.ShowObject(collider,showCollider)

    if objData.endFunc then
        objData.endFunc(spine)
    end
end

function LWonderObjectCtrl:Clear()
    for k,v in pairs(self._objList) do
        local spine= v.spine
        spine:Destroy()
    end
    self._objList = {}
end

function LWonderObjectCtrl:DestroyByKey(key)
    local spineData = self._objList[key]
    self._objList[key] = nil
    if spineData then
        local spine = spineData.spine
        spine:Destroy()
    end

end

function LWonderObjectCtrl:FindObjByKey(key)
    local spineData = self._objList[key]
    if spineData then
        return spineData.spine
    end
end

return LWonderObjectCtrl